-  match(Set dst (VectorSlice (Binary src1 src2) origin));
-  format %{ "vector_slice_const_origin $dst, $origin, $src1, $src2" %}
-  ins_encode %{
-    int vlen_enc = vector_length_encoding(this);
-    // src1 = [v2, v1], src2 = [v4, v3]
